--
-- Name: get_auth(text); Type: FUNCTION; Schema: pgbouncer; Owner: -
--

CREATE FUNCTION pgbouncer.get_auth(p_usename text) RETURNS TABLE(username text, password text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $_$
  BEGIN
      RAISE DEBUG 'PgBouncer auth request: %', p_usename;

      RETURN QUERY
      SELECT
          rolname::text,
          CASE WHEN rolvaliduntil < now()
              THEN null
              ELSE rolpassword::text
          END
      FROM pg_authid
      WHERE rolname=$1 and rolcanlogin;
  END;
  $_$;


--
-- Name: get_submission_documents_bucket_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_submission_documents_bucket_stats() RETURNS TABLE(bucket_id text, file_count bigint, total_bytes bigint, file_size_limit bigint, usage_ratio numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'storage'
    AS $$
begin
  if not exists (
    select 1
    from public.admin_users admin
    where admin.user_id = auth.uid()
  ) then
    raise exception 'Admin access required';
  end if;

  return query
  select
    bucket_row.id::text as bucket_id,
    count(storage_object.id)::bigint as file_count,
    coalesce(sum(coalesce((storage_object.metadata ->> 'size')::bigint, 0)), 0)::bigint as total_bytes,
    coalesce(bucket_row.file_size_limit, 0)::bigint as file_size_limit,
    case
      when coalesce(bucket_row.file_size_limit, 0) > 0 then
        round(
          coalesce(sum(coalesce((storage_object.metadata ->> 'size')::bigint, 0)), 0)::numeric
          / bucket_row.file_size_limit::numeric,
          6
        )
      else 0::numeric
    end as usage_ratio
  from storage.buckets bucket_row
  left join storage.objects storage_object
    on storage_object.bucket_id = bucket_row.id
  where bucket_row.id = 'submission-documents'
  group by bucket_row.id, bucket_row.file_size_limit;
end;
$$;


--
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.handle_new_user() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  INSERT INTO public.profiles (id, full_name)
  VALUES (NEW.id, COALESCE(NEW.raw_user_meta_data ->> 'full_name', ''));
  INSERT INTO public.user_roles (user_id, role)
  VALUES (NEW.id, 'user');
  RETURN NEW;
END;
$$;


--
-- Name: has_role(uuid, public.app_role); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.has_role(_user_id uuid, _role public.app_role) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.user_roles WHERE user_id = _user_id AND role = _role
  )
$$;


--
-- Name: is_admin(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_admin(uid uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select exists (
    select 1 from public.admin_users au where au.user_id = uid
  );
$$;


