--

CREATE FUNCTION public.match_rag_documents(query_embedding public.vector, match_count integer DEFAULT 5) RETURNS TABLE(id uuid, title text, content text, source text, similarity double precision)
    LANGUAGE sql STABLE
    AS $$
  select
    rag_documents.id,
    rag_documents.title,
    rag_documents.content,
    rag_documents.source,
    1 - (rag_documents.embedding <=> query_embedding) as similarity
  from rag_documents
  where rag_documents.embedding is not null
  order by rag_documents.embedding <=> query_embedding
  limit match_count;
$$;


--
-- Name: notify_consultants_on_request(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_consultants_on_request() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Insert notifications for all consultants who serve the request's category
  INSERT INTO public.notifications (user_id, type, title, message, related_id)
  SELECT 
    cc.user_id,
    'new_service_request',
    'Yeni Hizmet Talebi!',
    '"' || NEW.title || '" başlıklı yeni bir ' || NEW.category || ' talebi oluşturuldu.',
    NEW.id
  FROM public.consultant_categories cc
  WHERE cc.category = NEW.category
    AND cc.user_id != NEW.user_id;
  
  RETURN NEW;
END;
$$;


