-- Name: v_muhasebe_by_category; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_muhasebe_by_category WITH (security_invoker='true') AS
 SELECT category,
    count(*) AS record_count,
    COALESCE(sum(amount) FILTER (WHERE (currency = 'TRY'::public.currency_code)), (0)::numeric) AS total_try
   FROM public.expenses
  GROUP BY category;


--
-- Name: v_muhasebe_by_person; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_muhasebe_by_person WITH (security_invoker='true') AS
 SELECT person,
    count(*) AS record_count,
    COALESCE(sum(amount) FILTER (WHERE (currency = 'TRY'::public.currency_code)), (0)::numeric) AS total_try,
    COALESCE(sum(amount) FILTER (WHERE ((currency = 'TRY'::public.currency_code) AND (status = 'odendi'::public.expense_status))), (0)::numeric) AS paid_try,
    COALESCE(sum(amount) FILTER (WHERE ((currency = 'TRY'::public.currency_code) AND (status = 'bekliyor'::public.expense_status))), (0)::numeric) AS pending_try
   FROM public.expenses
  GROUP BY person;


--
-- Name: v_muhasebe_cashflow_monthly; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_muhasebe_cashflow_monthly WITH (security_invoker='true') AS
 WITH months AS (
         SELECT generate_series(1, 12) AS month_num
        ), expense_monthly AS (
         SELECT (EXTRACT(month FROM expenses.expense_date))::integer AS month_num,
            (EXTRACT(year FROM expenses.expense_date))::integer AS year_num,
            sum(expenses.amount) FILTER (WHERE (expenses.currency = 'TRY'::public.currency_code)) AS total_try,
            sum(expenses.amount) FILTER (WHERE ((expenses.currency = 'TRY'::public.currency_code) AND (expenses.person = 'burak'::public.person_type))) AS burak_try,
            sum(expenses.amount) FILTER (WHERE ((expenses.currency = 'TRY'::public.currency_code) AND (expenses.person = 'baris'::public.person_type))) AS baris_try,
            sum(expenses.amount) FILTER (WHERE ((expenses.currency = 'TRY'::public.currency_code) AND (expenses.person = 'ortak'::public.person_type))) AS ortak_try,
            sum(expenses.amount) FILTER (WHERE ((expenses.currency = 'TRY'::public.currency_code) AND (expenses.status = 'odendi'::public.expense_status))) AS paid_try,
            sum(expenses.amount) FILTER (WHERE ((expenses.currency = 'TRY'::public.currency_code) AND (expenses.status = 'bekliyor'::public.expense_status))) AS pending_try
           FROM public.expenses
          GROUP BY ((EXTRACT(month FROM expenses.expense_date))::integer), ((EXTRACT(year FROM expenses.expense_date))::integer)
        ), income_monthly AS (
         SELECT (EXTRACT(month FROM incomes.income_date))::integer AS month_num,
            (EXTRACT(year FROM incomes.income_date))::integer AS year_num,
            sum(incomes.amount) FILTER (WHERE (incomes.currency = 'TRY'::public.currency_code)) AS total_try,
            sum(incomes.amount) FILTER (WHERE ((incomes.currency = 'TRY'::public.currency_code) AND (incomes.status = 'tahsil_edildi'::public.income_status))) AS collected_try,
            sum(incomes.amount) FILTER (WHERE ((incomes.currency = 'TRY'::public.currency_code) AND (incomes.status = 'bekliyor'::public.income_status))) AS pending_try
           FROM public.incomes
          GROUP BY ((EXTRACT(month FROM incomes.income_date))::integer), ((EXTRACT(year FROM incomes.income_date))::integer)
        )
 SELECT COALESCE(em.year_num, im.year_num, (EXTRACT(year FROM CURRENT_DATE))::integer) AS year_num,
    m.month_num,
    COALESCE(im.total_try, (0)::numeric) AS income_try,
    COALESCE(em.total_try, (0)::numeric) AS expense_try,
    (COALESCE(im.total_try, (0)::numeric) - COALESCE(em.total_try, (0)::numeric)) AS net_try,
    COALESCE(em.burak_try, (0)::numeric) AS burak_try,
    COALESCE(em.baris_try, (0)::numeric) AS baris_try,
    COALESCE(em.ortak_try, (0)::numeric) AS ortak_try,
    COALESCE(em.paid_try, (0)::numeric) AS expense_paid_try,
    COALESCE(em.pending_try, (0)::numeric) AS expense_pending_try,
    COALESCE(im.collected_try, (0)::numeric) AS income_collected_try,
    COALESCE(im.pending_try, (0)::numeric) AS income_pending_try
   FROM ((months m
     LEFT JOIN expense_monthly em ON ((em.month_num = m.month_num)))
     LEFT JOIN income_monthly im ON ((im.month_num = m.month_num)))
  ORDER BY m.month_num;


--
-- Name: v_muhasebe_kpi; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_muhasebe_kpi WITH (security_invoker='true') AS
 SELECT COALESCE(( SELECT sum(expenses.amount) AS sum
           FROM public.expenses
          WHERE (expenses.currency = 'TRY'::public.currency_code)), (0)::numeric) AS total_expense_try,
    COALESCE(( SELECT sum(incomes.amount) AS sum
           FROM public.incomes
          WHERE (incomes.currency = 'TRY'::public.currency_code)), (0)::numeric) AS total_income_try,
    (COALESCE(( SELECT sum(incomes.amount) AS sum
           FROM public.incomes
          WHERE (incomes.currency = 'TRY'::public.currency_code)), (0)::numeric) - COALESCE(( SELECT sum(expenses.amount) AS sum
           FROM public.expenses
          WHERE (expenses.currency = 'TRY'::public.currency_code)), (0)::numeric)) AS net_position_try,
    COALESCE(( SELECT sum(expenses.amount) AS sum
           FROM public.expenses
          WHERE ((expenses.currency = 'TRY'::public.currency_code) AND (expenses.status = 'bekliyor'::public.expense_status))), (0)::numeric) AS pending_expense_try,
    COALESCE(( SELECT sum(incomes.amount) AS sum
           FROM public.incomes
          WHERE ((incomes.currency = 'TRY'::public.currency_code) AND (incomes.status = 'bekliyor'::public.income_status))), (0)::numeric) AS pending_income_try,
    (( SELECT count(*) AS count
           FROM public.expenses) + ( SELECT count(*) AS count
           FROM public.incomes)) AS total_records;


