20260406104636	{"-- Create submissions table for all form registrations\nCREATE TABLE public.submissions (\n  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,\n  form_type TEXT NOT NULL DEFAULT 'register',\n  category TEXT,\n  fullname TEXT NOT NULL,\n  country TEXT NOT NULL,\n  city TEXT NOT NULL,\n  business TEXT,\n  field TEXT NOT NULL,\n  email TEXT NOT NULL,\n  phone TEXT NOT NULL,\n  description TEXT,\n  contest_interest BOOLEAN DEFAULT false,\n  linkedin TEXT,\n  instagram TEXT,\n  tiktok TEXT,\n  facebook TEXT,\n  twitter TEXT,\n  website TEXT,\n  consent BOOLEAN NOT NULL DEFAULT false,\n  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()\n)","-- Enable RLS\nALTER TABLE public.submissions ENABLE ROW LEVEL SECURITY","-- Allow anyone to insert (public form)\nCREATE POLICY \\"Anyone can submit a registration\\"\n  ON public.submissions\n  FOR INSERT\n  TO anon, authenticated\n  WITH CHECK (true)","-- Only authenticated users can read (admin)\nCREATE POLICY \\"Authenticated users can read submissions\\"\n  ON public.submissions\n  FOR SELECT\n  TO authenticated\n  USING (true)"}	435b29f1-111a-44a7-8840-41211d0a1c6a
20260406193000	{"-- Restrict submission reads to explicit admin users and add review metadata.\n\nCREATE TABLE public.admin_users (\n  user_id UUID NOT NULL PRIMARY KEY,\n  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()\n)","ALTER TABLE public.admin_users ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Users can read their own admin membership\\"\n  ON public.admin_users\n  FOR SELECT\n  TO authenticated\n  USING (auth.uid() = user_id)","DROP POLICY IF EXISTS \\"Authenticated users can read submissions\\" ON public.submissions","ALTER TABLE public.submissions\n  ADD COLUMN status TEXT NOT NULL DEFAULT 'new' CHECK (status IN ('new', 'contacted', 'archived')),\n  ADD COLUMN notes TEXT,\n  ADD COLUMN reviewed_at TIMESTAMP WITH TIME ZONE,\n  ADD COLUMN reviewed_by UUID REFERENCES public.admin_users(user_id)","CREATE INDEX submissions_created_at_idx ON public.submissions (created_at DESC)","CREATE INDEX submissions_form_type_idx ON public.submissions (form_type)","CREATE INDEX submissions_category_idx ON public.submissions (category)","CREATE INDEX submissions_status_idx ON public.submissions (status)","CREATE POLICY \\"Admin users can read submissions\\"\n  ON public.submissions\n  FOR SELECT\n  TO authenticated\n  USING (\n    EXISTS (\n      SELECT 1\n      FROM public.admin_users admin\n      WHERE admin.user_id = auth.uid()\n    )\n  )","CREATE POLICY \\"Admin users can update submissions\\"\n  ON public.submissions\n  FOR UPDATE\n  TO authenticated\n  USING (\n    EXISTS (\n      SELECT 1\n      FROM public.admin_users admin\n      WHERE admin.user_id = auth.uid()\n    )\n  )\n  WITH CHECK (\n    EXISTS (\n      SELECT 1\n      FROM public.admin_users admin\n      WHERE admin.user_id = auth.uid()\n    )\n  )"}	admin_and_submission_workflow
