20260424143000	{"-- Extend advisor records with contact details and per-channel contacted state.\n\nalter table public.advisor_social_media_links\n  add column if not exists name text not null default 'İsimsiz',\n  add column if not exists email text,\n  add column if not exists phone text,\n  add column if not exists whatsapp text,\n  add column if not exists instagram text,\n  add column if not exists contacted_whatsapp boolean not null default false,\n  add column if not exists contacted_instagram boolean not null default false,\n  add column if not exists contacted_email boolean not null default false,\n  add column if not exists contacted_phone boolean not null default false","create index if not exists advisor_social_media_links_name_idx\n  on public.advisor_social_media_links (name)","update public.advisor_social_media_links\nset instagram = link\nwhere instagram is null\n  and link is not null"}	extend_advisor_contact_tracking
20260421161000	{"ALTER TABLE public.submissions\n  ADD COLUMN IF NOT EXISTS document_url text,\n  ADD COLUMN IF NOT EXISTS document_name text,\n  ADD COLUMN IF NOT EXISTS offers_needs text,\n  ADD COLUMN IF NOT EXISTS documents jsonb NOT NULL DEFAULT '[]'::jsonb","INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)\nVALUES (\n  'submission-documents',\n  'submission-documents',\n  true,\n  10485760,\n  ARRAY[\n    'application/pdf',\n    'application/msword',\n    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',\n    'image/jpeg',\n    'image/png',\n    'image/webp'\n  ]\n)\nON CONFLICT (id) DO UPDATE\nSET public = EXCLUDED.public,\n    file_size_limit = EXCLUDED.file_size_limit,\n    allowed_mime_types = EXCLUDED.allowed_mime_types","DROP POLICY IF EXISTS \\"Anyone can upload submission documents\\" ON storage.objects","CREATE POLICY \\"Anyone can upload submission documents\\"\n  ON storage.objects\n  FOR INSERT\n  TO anon, authenticated\n  WITH CHECK (bucket_id = 'submission-documents')","DROP POLICY IF EXISTS \\"Anyone can read submission documents\\" ON storage.objects","CREATE POLICY \\"Anyone can read submission documents\\"\n  ON storage.objects\n  FOR SELECT\n  TO anon, authenticated\n  USING (bucket_id = 'submission-documents')","CREATE TABLE IF NOT EXISTS public.matches (\n  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,\n  source_submission_id uuid NOT NULL REFERENCES public.submissions(id) ON DELETE CASCADE,\n  matched_submission_id uuid NOT NULL REFERENCES public.submissions(id) ON DELETE CASCADE,\n  match_type text NOT NULL DEFAULT 'offer-need',\n  match_score numeric,\n  match_reason text,\n  notified_source boolean NOT NULL DEFAULT false,\n  notified_target boolean NOT NULL DEFAULT false,\n  created_at timestamptz NOT NULL DEFAULT now(),\n  UNIQUE (source_submission_id, matched_submission_id)\n)","CREATE INDEX IF NOT EXISTS idx_matches_source ON public.matches(source_submission_id)","CREATE INDEX IF NOT EXISTS idx_matches_target ON public.matches(matched_submission_id)","ALTER TABLE public.matches ENABLE ROW LEVEL SECURITY","DROP POLICY IF EXISTS \\"Authenticated users can read matches\\" ON public.matches","CREATE POLICY \\"Authenticated users can read matches\\"\nON public.matches\nFOR SELECT\nTO authenticated\nUSING (true)","DROP POLICY IF EXISTS \\"System can create matches\\" ON public.matches"}	add_matching_and_documents
20260422113000	{"CREATE TABLE IF NOT EXISTS public.referral_codes (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  code TEXT NOT NULL UNIQUE,\n  code_prefix TEXT NOT NULL,\n  type_key TEXT NOT NULL,\n  type_char TEXT NOT NULL,\n  source_key TEXT NOT NULL,\n  source_char TEXT NOT NULL,\n  referral_date DATE NOT NULL,\n  month_char TEXT NOT NULL,\n  year_short TEXT NOT NULL,\n  random_part TEXT NOT NULL,\n  check_char TEXT NOT NULL,\n  note TEXT,\n  is_active BOOLEAN NOT NULL DEFAULT true,\n  is_used BOOLEAN NOT NULL DEFAULT false,\n  used_by UUID REFERENCES public.admin_users(user_id) ON DELETE SET NULL,\n  used_at TIMESTAMPTZ,\n  created_by UUID REFERENCES public.admin_users(user_id) ON DELETE SET NULL,\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now()\n)","CREATE UNIQUE INDEX IF NOT EXISTS referral_codes_code_idx\n  ON public.referral_codes (code)","CREATE INDEX IF NOT EXISTS referral_codes_created_at_idx\n  ON public.referral_codes (created_at DESC)","CREATE INDEX IF NOT EXISTS referral_codes_type_source_date_idx\n  ON public.referral_codes (type_key, source_key, referral_date)","ALTER TABLE public.referral_codes ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Admin users can read referral codes\\"\n  ON public.referral_codes\n  FOR SELECT\n  TO authenticated\n  USING (\n    EXISTS (\n      SELECT 1\n      FROM public.admin_users admin\n      WHERE admin.user_id = auth.uid()\n    )\n  )","CREATE POLICY \\"Admin users can insert referral codes\\"\n  ON public.referral_codes\n  FOR INSERT\n  TO authenticated\n  WITH CHECK (\n    EXISTS (\n      SELECT 1\n      FROM public.admin_users admin\n      WHERE admin.user_id = auth.uid()\n    )\n  )","CREATE POLICY \\"Admin users can update referral codes\\"\n  ON public.referral_codes\n  FOR UPDATE\n  TO authenticated\n  USING (\n    EXISTS (\n      SELECT 1\n      FROM public.admin_users admin\n      WHERE admin.user_id = auth.uid()\n    )\n  )\n  WITH CHECK (\n    EXISTS (\n      SELECT 1\n      FROM public.admin_users admin\n      WHERE admin.user_id = auth.uid()\n    )\n  )"}	add_referral_codes_table
20260422150000	{"DO $$\nBEGIN\n  IF EXISTS (\n    SELECT 1\n    FROM information_schema.tables\n    WHERE table_schema = 'public' AND table_name = 'referral_codes'\n  ) AND EXISTS (\n    SELECT 1\n    FROM information_schema.columns\n    WHERE table_schema = 'public' AND table_name = 'referral_codes' AND column_name = 'source_key'\n  ) THEN\n    IF EXISTS (\n      SELECT 1\n      FROM information_schema.tables\n      WHERE table_schema = 'public' AND table_name = 'referral_codes_legacy'\n    ) THEN\n      EXECUTE 'DROP TABLE public.referral_codes_legacy';\n    END IF;\n    EXECUTE 'ALTER TABLE public.referral_codes RENAME TO referral_codes_legacy';\n  END IF;\nEND $$","CREATE TABLE IF NOT EXISTS public.referral_sources (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  name TEXT NOT NULL,\n  code TEXT NOT NULL UNIQUE,\n  is_active BOOLEAN NOT NULL DEFAULT true,\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  CONSTRAINT referral_sources_code_format CHECK (code ~ '^[A-Z]{2}$')\n)","CREATE TABLE IF NOT EXISTS public.referral_types (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  name TEXT NOT NULL,\n  code TEXT NOT NULL UNIQUE,\n  is_active BOOLEAN NOT NULL DEFAULT true,\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  CONSTRAINT referral_types_code_format CHECK (code ~ '^[A-Z]{2}$')\n)","INSERT INTO public.referral_sources (name, code)\nVALUES\n  ('WhatsApp', 'WA'),\n  ('Instagram', 'IG'),\n  ('LinkedIn', 'LI')\nON CONFLICT (code) DO NOTHING","INSERT INTO public.referral_types (name, code)\nVALUES\n  ('Normal', 'NM'),\n  ('Partner', 'PT'),\n  ('Campaign', 'CM'),\n  ('Test', 'TS')\nON CONFLICT (code) DO NOTHING","CREATE TABLE IF NOT EXISTS public.referral_codes (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  code TEXT NOT NULL UNIQUE,\n  source_id UUID NOT NULL REFERENCES public.referral_sources(id),\n  type_id UUID NOT NULL REFERENCES public.referral_types(id),\n  source_code TEXT NOT NULL,\n  type_code TEXT NOT NULL,\n  month_num INTEGER NOT NULL CHECK (month_num BETWEEN 1 AND 12),\n  year_short TEXT NOT NULL CHECK (year_short ~ '^[0-9]{2}$'),\n  random_part TEXT NOT NULL,\n  note TEXT,\n  is_active BOOLEAN NOT NULL DEFAULT true,\n  is_used BOOLEAN NOT NULL DEFAULT false,\n  used_at TIMESTAMPTZ,\n  created_by UUID REFERENCES public.admin_users(user_id) ON DELETE SET NULL,\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now()\n)","CREATE UNIQUE INDEX IF NOT EXISTS referral_codes_code_idx\n  ON public.referral_codes (code)","CREATE INDEX IF NOT EXISTS referral_codes_lookup_idx\n  ON public.referral_codes (source_id, type_id, created_at DESC)","CREATE INDEX IF NOT EXISTS referral_codes_usage_idx\n  ON public.referral_codes (is_active, is_used)","DO $$\nBEGIN\n  IF EXISTS (\n    SELECT 1\n    FROM information_schema.tables\n    WHERE table_schema = 'public' AND table_name = 'referral_codes_legacy'\n  ) THEN\n    INSERT INTO public.referral_codes (\n      code,\n      source_id,\n      type_id,\n      source_code,\n      type_code,\n      month_num,\n      year_short,\n      random_part,\n      note,\n      is_active,\n      is_used,\n      used_at,\n      created_by,\n      created_at\n    )\n    SELECT\n      legacy.code,\n      source_match.id,\n      type_match.id,\n      source_match.code,\n      type_match.code,\n      COALESCE(EXTRACT(MONTH FROM legacy.referral_date)::INT, 1),\n      COALESCE(TO_CHAR(legacy.referral_date, 'YY'), RIGHT(REGEXP_REPLACE(legacy.code, '^.*?([0-9]{2})-[A-Z2-9]+$', '\\\\1'), 2)),\n      COALESCE(REGEXP_REPLACE(legacy.code, '^.*-([A-Z2-9]+)$', '\\\\1'), legacy.random_part),\n      legacy.note,\n      COALESCE(legacy.is_active, true),\n      COALESCE(legacy.is_used, false),\n      legacy.used_at,\n      legacy.created_by,\n      COALESCE(legacy.created_at, now())\n    FROM public.referral_codes_legacy legacy\n    JOIN LATERAL (\n      SELECT rs.id, rs.code\n      FROM public.referral_sources rs\n      WHERE rs.code = CASE\n        WHEN legacy.source_key = 'whatsapp' THEN 'WA'\n        WHEN legacy.source_key = 'instagram' THEN 'IG'\n        WHEN legacy.source_key = 'linkedin' THEN 'LI'\n        ELSE 'LI'\n      END\n      LIMIT 1\n    ) AS source_match ON true\n    JOIN LATERAL (\n      SELECT rt.id, rt.code\n      FROM public.referral_types rt\n      WHERE rt.code = CASE\n        WHEN legacy.type_key = 'normal' THEN 'NM'\n        WHEN legacy.type_key = 'partner' THEN 'PT'\n        WHEN legacy.type_key = 'campaign' THEN 'CM'\n        ELSE 'TS'\n      END\n      LIMIT 1\n    ) AS type_match ON true\n    ON CONFLICT (code) DO NOTHING;\n  END IF;\nEND $$","ALTER TABLE public.referral_sources ENABLE ROW LEVEL SECURITY","ALTER TABLE public.referral_types ENABLE ROW LEVEL SECURITY","ALTER TABLE public.referral_codes ENABLE ROW LEVEL SECURITY","DROP POLICY IF EXISTS \\"Admin users can read referral sources\\" ON public.referral_sources","DROP POLICY IF EXISTS \\"Admin users can insert referral sources\\" ON public.referral_sources","DROP POLICY IF EXISTS \\"Admin users can update referral sources\\" ON public.referral_sources","DROP POLICY IF EXISTS \\"Admin users can read referral types\\" ON public.referral_types","DROP POLICY IF EXISTS \\"Admin users can insert referral types\\" ON public.referral_types","DROP POLICY IF EXISTS \\"Admin users can update referral types\\" ON public.referral_types","DROP POLICY IF EXISTS \\"Admin users can read referral codes\\" ON public.referral_codes","DROP POLICY IF EXISTS \\"Admin users can insert referral codes\\" ON public.referral_codes","DROP POLICY IF EXISTS \\"Admin users can update referral codes\\" ON public.referral_codes","CREATE POLICY \\"Admin users can read referral sources\\"\n  ON public.referral_sources\n  FOR SELECT\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can insert referral sources\\"\n  ON public.referral_sources\n  FOR INSERT\n  TO authenticated\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can update referral sources\\"\n  ON public.referral_sources\n  FOR UPDATE\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can read referral types\\"\n  ON public.referral_types\n  FOR SELECT\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can insert referral types\\"\n  ON public.referral_types\n  FOR INSERT\n  TO authenticated\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can update referral types\\"\n  ON public.referral_types\n  FOR UPDATE\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can read referral codes\\"\n  ON public.referral_codes\n  FOR SELECT\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can insert referral codes\\"\n  ON public.referral_codes\n  FOR INSERT\n  TO authenticated\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can update referral codes\\"\n  ON public.referral_codes\n  FOR UPDATE\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))"}	referral_domain_normalization
20260422170000	{BEGIN,"CREATE TABLE IF NOT EXISTS public.referral_groups (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  name TEXT NOT NULL,\n  code TEXT NOT NULL UNIQUE,\n  is_active BOOLEAN NOT NULL DEFAULT true,\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  CONSTRAINT referral_groups_code_format CHECK (code ~ '^[A-Z]{2}$')\n)","INSERT INTO public.referral_groups (name, code)\nVALUES ('Genel', 'GN')\nON CONFLICT (code) DO NOTHING","ALTER TABLE public.referral_codes\n  ADD COLUMN IF NOT EXISTS group_id UUID REFERENCES public.referral_groups(id),\n  ADD COLUMN IF NOT EXISTS group_code TEXT,\n  ADD COLUMN IF NOT EXISTS valid_from DATE,\n  ADD COLUMN IF NOT EXISTS valid_until DATE,\n  ADD COLUMN IF NOT EXISTS usage_count INTEGER NOT NULL DEFAULT 0","DO $$\nDECLARE\n  default_group_id UUID;\nBEGIN\n  SELECT id INTO default_group_id\n  FROM public.referral_groups\n  WHERE code = 'GN'\n  LIMIT 1;\n\n  IF default_group_id IS NULL THEN\n    INSERT INTO public.referral_groups (name, code)\n    VALUES ('Genel', 'GN')\n    RETURNING id INTO default_group_id;\n  END IF;\n\n  UPDATE public.referral_codes\n  SET\n    group_id = COALESCE(group_id, default_group_id),\n    group_code = COALESCE(group_code, 'GN'),\n    valid_from = COALESCE(valid_from, COALESCE(created_at::date, CURRENT_DATE)),\n    valid_until = COALESCE(valid_until, COALESCE(created_at::date, CURRENT_DATE) + INTERVAL '1 year'),\n    usage_count = COALESCE(usage_count, 0)\n  WHERE group_id IS NULL\n    OR group_code IS NULL\n    OR valid_from IS NULL\n    OR valid_until IS NULL\n    OR usage_count IS NULL;\nEND $$","ALTER TABLE public.referral_codes\n  ALTER COLUMN group_id SET NOT NULL,\n  ALTER COLUMN group_code SET NOT NULL,\n  ALTER COLUMN valid_from SET NOT NULL,\n  ALTER COLUMN valid_until SET NOT NULL","ALTER TABLE public.referral_codes\n  DROP CONSTRAINT IF EXISTS referral_codes_valid_window","ALTER TABLE public.referral_codes\n  ADD CONSTRAINT referral_codes_valid_window CHECK (valid_until >= valid_from)","CREATE INDEX IF NOT EXISTS referral_codes_group_lookup_idx\n  ON public.referral_codes (group_id, valid_from, valid_until)","CREATE INDEX IF NOT EXISTS referral_codes_usage_count_idx\n  ON public.referral_codes (usage_count DESC, used_at DESC NULLS LAST)","ALTER TABLE public.submissions\n  ADD COLUMN IF NOT EXISTS referral_code_id UUID REFERENCES public.referral_codes(id)","CREATE INDEX IF NOT EXISTS submissions_referral_code_id_idx\n  ON public.submissions (referral_code_id)","UPDATE public.submissions AS submissions\nSET referral_code_id = referral_codes.id\nFROM public.referral_codes AS referral_codes\nWHERE submissions.referral_code_id IS NULL\n  AND submissions.referral_code IS NOT NULL\n  AND BTRIM(submissions.referral_code) <> ''\n  AND UPPER(BTRIM(submissions.referral_code)) = UPPER(referral_codes.code)","CREATE TABLE IF NOT EXISTS public.referral_code_usages (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  referral_code_id UUID NOT NULL REFERENCES public.referral_codes(id) ON DELETE CASCADE,\n  submission_id UUID NOT NULL REFERENCES public.submissions(id) ON DELETE CASCADE,\n  used_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  full_name TEXT,\n  email TEXT,\n  UNIQUE (submission_id)\n)","CREATE INDEX IF NOT EXISTS referral_code_usages_referral_idx\n  ON public.referral_code_usages (referral_code_id, used_at DESC)","ALTER TABLE public.referral_groups ENABLE ROW LEVEL SECURITY","ALTER TABLE public.referral_code_usages ENABLE ROW LEVEL SECURITY","DROP POLICY IF EXISTS \\"Admin users can read referral groups\\" ON public.referral_groups","DROP POLICY IF EXISTS \\"Admin users can insert referral groups\\" ON public.referral_groups","DROP POLICY IF EXISTS \\"Admin users can update referral groups\\" ON public.referral_groups","DROP POLICY IF EXISTS \\"Admin users can read referral code usages\\" ON public.referral_code_usages","CREATE POLICY \\"Admin users can read referral groups\\"\n  ON public.referral_groups\n  FOR SELECT\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can insert referral groups\\"\n  ON public.referral_groups\n  FOR INSERT\n  TO authenticated\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can update referral groups\\"\n  ON public.referral_groups\n  FOR UPDATE\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can read referral code usages\\"\n  ON public.referral_code_usages\n  FOR SELECT\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE OR REPLACE FUNCTION public.validate_and_bind_referral_code(\n  input_code TEXT,\n  reference_time TIMESTAMPTZ DEFAULT now()\n)\nRETURNS TABLE (\n  status TEXT,\n  referral_code_id UUID,\n  message TEXT,\n  normalized_code TEXT,\n  source_code TEXT,\n  group_code TEXT,\n  type_code TEXT,\n  valid_from DATE,\n  valid_until DATE\n)\nLANGUAGE plpgsql\nSECURITY DEFINER\nSET search_path = public\nAS $$\nDECLARE\n  candidate_code TEXT := UPPER(BTRIM(COALESCE(input_code, '')));\n  reference_date DATE := COALESCE(reference_time, now())::date;\n  code_row RECORD;\nBEGIN\n  IF candidate_code = '' THEN\n    RETURN QUERY\n    SELECT\n      'missing'::TEXT,\n      NULL::UUID,\n      'Referral code is empty.'::TEXT,\n      NULL::TEXT,\n      NULL::TEXT,\n      NULL::TEXT,\n      NULL::TEXT,\n      NULL::DATE,\n      NULL::DATE;\n    RETURN;\n  END IF;\n\n  SELECT\n    referral_codes.id,\n    referral_codes.code,\n    referral_codes.is_active,\n    referral_codes.source_code,\n    referral_codes.group_code,\n    referral_codes.type_code,\n    referral_codes.valid_from,\n    referral_codes.valid_until,\n    referral_sources.is_active AS source_is_active,\n    referral_groups.is_active AS group_is_active,\n    referral_types.is_active AS type_is_active\n  INTO code_row\n  FROM public.referral_codes AS referral_codes\n  JOIN public.referral_sources AS referral_sources ON referral_sources.id = referral_codes.source_id\n  JOIN public.referral_groups AS referral_groups ON referral_groups.id = referral_codes.group_id\n  JOIN public.referral_types AS referral_types ON referral_types.id = referral_codes.type_id\n  WHERE UPPER(referral_codes.code) = candidate_code\n  ORDER BY referral_codes.created_at DESC\n  LIMIT 1;\n\n  IF NOT FOUND THEN\n    RETURN QUERY\n    SELECT\n      'not_found'::TEXT,\n      NULL::UUID,\n      'Referral code not found.'::TEXT,\n      candidate_code,\n      NULL::TEXT,\n      NULL::TEXT,\n      NULL::TEXT,\n      NULL::DATE,\n      NULL::DATE;\n    RETURN;\n  END IF;\n\n  IF NOT code_row.is_active OR NOT code_row.source_is_active OR NOT code_row.group_is_active OR NOT code_row.type_is_active THEN\n    RETURN QUERY\n    SELECT\n      'inactive'::TEXT,\n      code_row.id,\n      'Referral code is inactive.'::TEXT,\n      code_row.code,\n      code_row.source_code,\n      code_row.group_code,\n      code_row.type_code,\n      code_row.valid_from,\n      code_row.valid_until;\n    RETURN;\n  END IF;\n\n  IF reference_date < code_row.valid_from THEN\n    RETURN QUERY\n    SELECT\n      'out_of_window'::TEXT,\n      code_row.id,\n      'Referral code is not active yet.'::TEXT,\n      code_row.code,\n      code_row.source_code,\n      code_row.group_code,\n      code_row.type_code,\n      code_row.valid_from,\n      code_row.valid_until;\n    RETURN;\n  END IF;\n\n  IF reference_date > code_row.valid_until THEN\n    RETURN QUERY\n    SELECT\n      'expired'::TEXT,\n      code_row.id,\n      'Referral code is expired.'::TEXT,\n      code_row.code,\n      code_row.source_code,\n      code_row.group_code,\n      code_row.type_code,\n      code_row.valid_from,\n      code_row.valid_until;\n    RETURN;\n  END IF;\n\n  RETURN QUERY\n  SELECT\n    'valid'::TEXT,\n    code_row.id,\n    'Referral code is valid.'::TEXT,\n    code_row.code,\n    code_row.source_code,\n    code_row.group_code,\n    code_row.type_code,\n    code_row.valid_from,\n    code_row.valid_until;\nEND;\n$$","GRANT EXECUTE ON FUNCTION public.validate_and_bind_referral_code(TEXT, TIMESTAMPTZ) TO anon, authenticated","CREATE OR REPLACE FUNCTION public.submissions_apply_referral_code()\nRETURNS TRIGGER\nLANGUAGE plpgsql\nSECURITY DEFINER\nSET search_path = public\nAS $$\nDECLARE\n  validation_result RECORD;\n  normalized_referral_code TEXT;\nBEGIN\n  IF NEW.id IS NULL THEN\n    NEW.id := gen_random_uuid();\n  END IF;\n\n  IF NEW.referral_code IS NULL OR BTRIM(NEW.referral_code) = '' THEN\n    NEW.referral_code := NULL;\n    NEW.referral_code_id := NULL;\n    RETURN NEW;\n  END IF;\n\n  normalized_referral_code := UPPER(BTRIM(NEW.referral_code));\n\n  SELECT * INTO validation_result\n  FROM public.validate_and_bind_referral_code(normalized_referral_code, COALESCE(NEW.created_at, now()))\n  LIMIT 1;\n\n  IF validation_result.status IS DISTINCT FROM 'valid' THEN\n    RAISE EXCEPTION USING\n      ERRCODE = 'P0001',\n      MESSAGE = COALESCE(validation_result.message, 'Referral code is invalid.'),\n      DETAIL = COALESCE(validation_result.status, 'invalid_referral_code'),\n      HINT = 'Use a valid and active referral code within its date range.';\n  END IF;\n\n  NEW.referral_code := validation_result.normalized_code;\n  NEW.referral_code_id := validation_result.referral_code_id;\n\n  RETURN NEW;\nEND;\n$$","CREATE OR REPLACE FUNCTION public.submissions_log_referral_usage()\nRETURNS TRIGGER\nLANGUAGE plpgsql\nSECURITY DEFINER\nSET search_path = public\nAS $$\nBEGIN\n  IF NEW.referral_code_id IS NULL THEN\n    RETURN NEW;\n  END IF;\n\n  UPDATE public.referral_codes\n  SET\n    usage_count = COALESCE(usage_count, 0) + 1,\n    is_used = true,\n    used_at = GREATEST(COALESCE(used_at, TIMESTAMPTZ 'epoch'), COALESCE(NEW.created_at, now()))\n  WHERE id = NEW.referral_code_id;\n\n  INSERT INTO public.referral_code_usages (referral_code_id, submission_id, used_at, full_name, email)\n  VALUES (\n    NEW.referral_code_id,\n    NEW.id,\n    COALESCE(NEW.created_at, now()),\n    NEW.fullname,\n    NEW.email\n  )\n  ON CONFLICT (submission_id) DO NOTHING;\n\n  RETURN NEW;\nEND;\n$$","DROP TRIGGER IF EXISTS submissions_apply_referral_code_trigger ON public.submissions","CREATE TRIGGER submissions_apply_referral_code_trigger\n  BEFORE INSERT ON public.submissions\n  FOR EACH ROW\n  EXECUTE FUNCTION public.submissions_apply_referral_code()","DROP TRIGGER IF EXISTS submissions_log_referral_usage_trigger ON public.submissions","CREATE TRIGGER submissions_log_referral_usage_trigger\n  AFTER INSERT ON public.submissions\n  FOR EACH ROW\n  EXECUTE FUNCTION public.submissions_log_referral_usage()",COMMIT}	referral_groups_and_validation
20260422190000	{BEGIN,"DROP POLICY IF EXISTS \\"Admin users can delete referral codes\\" ON public.referral_codes","CREATE POLICY \\"Admin users can delete referral codes\\"\n  ON public.referral_codes\n  FOR DELETE\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))",COMMIT}	add_referral_codes_delete_policy
