20260423140000	{BEGIN,"CREATE OR REPLACE FUNCTION public.validate_and_bind_referral_code(\n  input_code TEXT,\n  reference_time TIMESTAMPTZ DEFAULT now()\n)\nRETURNS TABLE (\n  status TEXT,\n  referral_code_id UUID,\n  message TEXT,\n  normalized_code TEXT\n)\nLANGUAGE plpgsql\nSECURITY DEFINER\nSET search_path = public\nAS $$\nDECLARE\n  candidate_code TEXT := UPPER(BTRIM(COALESCE(input_code, '')));\n  reference_date DATE := COALESCE(reference_time, now())::date;\n  code_row RECORD;\nBEGIN\n  IF candidate_code = '' THEN\n    RETURN QUERY\n    SELECT\n      'missing'::TEXT,\n      NULL::UUID,\n      'Referral code is empty.'::TEXT,\n      NULL::TEXT;\n    RETURN;\n  END IF;\n\n  SELECT\n    referral_codes.id,\n    referral_codes.code,\n    referral_codes.is_active,\n    referral_codes.source_code,\n    referral_codes.group_code,\n    referral_codes.type_code,\n    referral_codes.valid_from,\n    referral_codes.valid_until,\n    referral_sources.is_active AS source_is_active,\n    referral_groups.is_active AS group_is_active,\n    referral_types.is_active AS type_is_active\n  INTO code_row\n  FROM public.referral_codes AS referral_codes\n  JOIN public.referral_sources AS referral_sources ON referral_sources.id = referral_codes.source_id\n  JOIN public.referral_groups AS referral_groups ON referral_groups.id = referral_codes.group_id\n  JOIN public.referral_types AS referral_types ON referral_types.id = referral_codes.type_id\n  WHERE UPPER(referral_codes.code) = candidate_code\n  ORDER BY referral_codes.created_at DESC\n  LIMIT 1;\n\n  IF NOT FOUND THEN\n    RETURN QUERY\n    SELECT\n      'not_found'::TEXT,\n      NULL::UUID,\n      'Referral code not found.'::TEXT,\n      candidate_code;\n    RETURN;\n  END IF;\n\n  IF NOT code_row.is_active OR NOT code_row.source_is_active OR NOT code_row.group_is_active OR NOT code_row.type_is_active THEN\n    RETURN QUERY\n    SELECT\n      'inactive'::TEXT,\n      NULL::UUID,\n      'Referral code is inactive.'::TEXT,\n      NULL::TEXT;\n    RETURN;\n  END IF;\n\n  IF reference_date < code_row.valid_from THEN\n    RETURN QUERY\n    SELECT\n      'out_of_window'::TEXT,\n      NULL::UUID,\n      'Referral code is not active yet.'::TEXT,\n      NULL::TEXT;\n    RETURN;\n  END IF;\n\n  IF reference_date > code_row.valid_until THEN\n    RETURN QUERY\n    SELECT\n      'expired'::TEXT,\n      NULL::UUID,\n      'Referral code is expired.'::TEXT,\n      NULL::TEXT;\n    RETURN;\n  END IF;\n\n  RETURN QUERY\n  SELECT\n    'valid'::TEXT,\n    code_row.id,\n    'Referral code is valid.'::TEXT,\n    code_row.code;\nEND;\n$$",COMMIT}	reduce_referral_validation_leakage
20260424110000	{BEGIN,"CREATE TABLE IF NOT EXISTS public.marquee_items (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  type TEXT NOT NULL CHECK (type IN ('news', 'stat', 'announcement')),\n  slug TEXT,\n  title TEXT NOT NULL,\n  summary TEXT NOT NULL,\n  detail_content TEXT,\n  image_url TEXT,\n  image_alt TEXT,\n  metric_value TEXT,\n  link_enabled BOOLEAN NOT NULL DEFAULT false,\n  sort_order INTEGER NOT NULL DEFAULT 0,\n  is_active BOOLEAN NOT NULL DEFAULT true,\n  published_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  CONSTRAINT marquee_items_slug_format CHECK (\n    slug IS NULL OR slug ~ '^[a-z0-9]+(?:-[a-z0-9]+)*$'\n  ),\n  CONSTRAINT marquee_items_link_slug_required CHECK (\n    link_enabled = false OR (slug IS NOT NULL AND BTRIM(slug) <> '')\n  )\n)","CREATE UNIQUE INDEX IF NOT EXISTS marquee_items_slug_unique_idx\n  ON public.marquee_items (slug)\n  WHERE slug IS NOT NULL","CREATE INDEX IF NOT EXISTS marquee_items_public_lookup_idx\n  ON public.marquee_items (is_active, sort_order, published_at DESC)","CREATE OR REPLACE FUNCTION public.set_marquee_items_updated_at()\nRETURNS TRIGGER\nLANGUAGE plpgsql\nAS $$\nBEGIN\n  NEW.updated_at = now();\n  RETURN NEW;\nEND;\n$$","DROP TRIGGER IF EXISTS set_marquee_items_updated_at ON public.marquee_items","CREATE TRIGGER set_marquee_items_updated_at\n  BEFORE UPDATE ON public.marquee_items\n  FOR EACH ROW\n  EXECUTE FUNCTION public.set_marquee_items_updated_at()","ALTER TABLE public.marquee_items ENABLE ROW LEVEL SECURITY","DROP POLICY IF EXISTS \\"Public can read active marquee items\\" ON public.marquee_items","DROP POLICY IF EXISTS \\"Admin users can read marquee items\\" ON public.marquee_items","DROP POLICY IF EXISTS \\"Admin users can insert marquee items\\" ON public.marquee_items","DROP POLICY IF EXISTS \\"Admin users can update marquee items\\" ON public.marquee_items","DROP POLICY IF EXISTS \\"Admin users can delete marquee items\\" ON public.marquee_items","CREATE POLICY \\"Public can read active marquee items\\"\n  ON public.marquee_items\n  FOR SELECT\n  TO anon, authenticated\n  USING (is_active = true)","CREATE POLICY \\"Admin users can read marquee items\\"\n  ON public.marquee_items\n  FOR SELECT\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can insert marquee items\\"\n  ON public.marquee_items\n  FOR INSERT\n  TO authenticated\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can update marquee items\\"\n  ON public.marquee_items\n  FOR UPDATE\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))\n  WITH CHECK (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","CREATE POLICY \\"Admin users can delete marquee items\\"\n  ON public.marquee_items\n  FOR DELETE\n  TO authenticated\n  USING (EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid()))","INSERT INTO public.marquee_items (\n  type,\n  slug,\n  title,\n  summary,\n  detail_content,\n  image_url,\n  image_alt,\n  metric_value,\n  link_enabled,\n  sort_order\n)\nVALUES\n  (\n    'stat',\n    'turk-diasporasi-164-ulke',\n    'Türk diasporası 164 ülkede görünür',\n    'CorteQS, şehir bazlı bağlantılarla küresel Türk topluluğunu tek ekosistemde toplamayı hedefliyor.',\n    'CorteQS, Türk diasporasının yaşadığı şehirlerde danışmanlar, işletmeler, topluluklar ve bireyler arasında güven odaklı bağlantılar kurmak için tasarlanmıştır. 164 ülkeye yayılan bu ağ, yerel ihtiyaçları küresel görünürlükle buluşturmayı amaçlar.',\n    'https://corteqs.net/og-image.png',\n    'CorteQS küresel diaspora ağı görseli',\n    '164 ülke',\n    true,\n    10\n  ),\n  (\n    'stat',\n    NULL,\n    '8.8 milyon kişilik küresel topluluk',\n    'Yurt dışında yaşayan Türkler için şehir, meslek ve ihtiyaç bazlı bağlantı alanı kuruluyor.',\n    NULL,\n    'https://corteqs.net/logocorteqsbig.png',\n    'CorteQS logo ve diaspora ağı',\n    '8.8 milyon',\n    false,\n    20\n  ),\n  (\n    'announcement',\n    'erken-kayit-duyurusu',\n    'Erken kayıt ve şehir elçisi başvuruları açık',\n    'Platform açılışı öncesi danışman, işletme, içerik üreticisi ve şehir elçisi adayları kayıt bırakabiliyor.',\n    'Erken kayıt süreci, CorteQS açılışı öncesinde topluluk yoğunluğunu ve şehir bazlı ihtiyaçları ölçmek için kullanılır. Başvurular danışman, işletme, dernek, içerik üreticisi, şehir elçisi ve bireysel kullanıcı kategorilerinde toplanır.',\n    'https://corteqs.net/og-image.png',\n    'CorteQS erken kayıt duyurusu',\n    NULL,\n    true,\n    30\n  )\nON CONFLICT DO NOTHING","INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)\nVALUES (\n  'newsimage',\n  'newsimage',\n  true,\n  5242880,\n  ARRAY['image/jpeg', 'image/png', 'image/webp', 'image/gif']\n)\nON CONFLICT (id) DO UPDATE\nSET\n  public = EXCLUDED.public,\n  file_size_limit = EXCLUDED.file_size_limit,\n  allowed_mime_types = EXCLUDED.allowed_mime_types","DROP POLICY IF EXISTS \\"Public can read news images\\" ON storage.objects","DROP POLICY IF EXISTS \\"Admin users can upload news images\\" ON storage.objects","DROP POLICY IF EXISTS \\"Admin users can update news images\\" ON storage.objects","DROP POLICY IF EXISTS \\"Admin users can delete news images\\" ON storage.objects","CREATE POLICY \\"Public can read news images\\"\n  ON storage.objects\n  FOR SELECT\n  TO anon, authenticated\n  USING (bucket_id = 'newsimage')","CREATE POLICY \\"Admin users can upload news images\\"\n  ON storage.objects\n  FOR INSERT\n  TO authenticated\n  WITH CHECK (\n    bucket_id = 'newsimage'\n    AND EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid())\n  )","CREATE POLICY \\"Admin users can update news images\\"\n  ON storage.objects\n  FOR UPDATE\n  TO authenticated\n  USING (\n    bucket_id = 'newsimage'\n    AND EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid())\n  )\n  WITH CHECK (\n    bucket_id = 'newsimage'\n    AND EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid())\n  )","CREATE POLICY \\"Admin users can delete news images\\"\n  ON storage.objects\n  FOR DELETE\n  TO authenticated\n  USING (\n    bucket_id = 'newsimage'\n    AND EXISTS (SELECT 1 FROM public.admin_users admin WHERE admin.user_id = auth.uid())\n  )",COMMIT}	add_marquee_items
20260424123000	{"-- Add shared admin-managed link tables used by the dashboard and landing admin.\n\ncreate table if not exists public.social_media_links (\n  id uuid primary key default gen_random_uuid(),\n  platform text not null default 'Diğer',\n  description text,\n  link text,\n  added_by text not null default 'UBT',\n  created_at timestamp with time zone not null default now(),\n  constraint social_media_links_platform_check\n    check (platform in ('Instagram', 'LinkedIn', 'Twitter (X)', 'YouTube', 'TikTok', 'Facebook', 'Reddit', 'Discord', 'Diğer')),\n  constraint social_media_links_added_by_check\n    check (added_by in ('UBT', 'Burak', 'Diğer'))\n)","create table if not exists public.advisor_social_media_links (\n  id uuid primary key default gen_random_uuid(),\n  platform text not null default 'Diğer',\n  description text,\n  link text,\n  added_by text not null default 'UBT',\n  created_at timestamp with time zone not null default now(),\n  constraint advisor_social_media_links_platform_check\n    check (platform in ('Instagram', 'LinkedIn', 'Twitter (X)', 'YouTube', 'TikTok', 'Facebook', 'Reddit', 'Discord', 'Diğer')),\n  constraint advisor_social_media_links_added_by_check\n    check (added_by in ('UBT', 'Burak', 'Diğer'))\n)","alter table public.social_media_links enable row level security","alter table public.advisor_social_media_links enable row level security","drop policy if exists \\"Allow all\\" on public.social_media_links","drop policy if exists \\"social_media_links_select_public\\" on public.social_media_links","drop policy if exists \\"social_media_links_all_authenticated\\" on public.social_media_links","drop policy if exists \\"social_media_links_insert_admin\\" on public.social_media_links","drop policy if exists \\"social_media_links_update_admin\\" on public.social_media_links","drop policy if exists \\"social_media_links_delete_admin\\" on public.social_media_links","drop policy if exists \\"Allow all\\" on public.advisor_social_medi