20260426170000	{"CREATE TABLE IF NOT EXISTS public.wa_users (\n  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,\n  wa_id TEXT,\n  city TEXT,\n  current_step TEXT,\n  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),\n  updated_at TIMESTAMP WITH TIME ZONE,\n  name TEXT,\n  surname TEXT,\n  country TEXT,\n  category TEXT,\n  note TEXT,\n  funnel_interest TEXT,\n  organization TEXT,\n  occupation_interest TEXT,\n  email TEXT,\n  phone TEXT,\n  discovery_source TEXT,\n  referral_code TEXT,\n  whatsapp_group_interest BOOLEAN,\n  privacy_consent BOOLEAN,\n  registration_status TEXT,\n  registration_completed_at TIMESTAMP WITH TIME ZONE\n)","ALTER TABLE public.submissions\n  ADD COLUMN IF NOT EXISTS source_type TEXT NOT NULL DEFAULT 'form'","ALTER TABLE public.wa_users\n  ADD COLUMN IF NOT EXISTS source_type TEXT NOT NULL DEFAULT 'wa'","UPDATE public.submissions\nSET source_type = 'chatbot'\nWHERE referral_source = 'ai-chat'\n  AND source_type = 'form'","UPDATE public.wa_users\nSET source_type = 'wa'\nWHERE source_type IS NULL\n   OR source_type <> 'wa'","DO $$\nBEGIN\n  IF NOT EXISTS (\n    SELECT 1\n    FROM pg_constraint\n    WHERE conname = 'submissions_source_type_check'\n      AND conrelid = 'public.submissions'::regclass\n  ) THEN\n    ALTER TABLE public.submissions\n      ADD CONSTRAINT submissions_source_type_check\n      CHECK (source_type IN ('form', 'chatbot'));\n  END IF;\n\n  IF NOT EXISTS (\n    SELECT 1\n    FROM pg_constraint\n    WHERE conname = 'wa_users_source_type_check'\n      AND conrelid = 'public.wa_users'::regclass\n  ) THEN\n    ALTER TABLE public.wa_users\n      ADD CONSTRAINT wa_users_source_type_check\n      CHECK (source_type = 'wa');\n  END IF;\nEND $$","CREATE INDEX IF NOT EXISTS submissions_source_type_idx\n  ON public.submissions (source_type)","CREATE INDEX IF NOT EXISTS wa_users_created_at_idx\n  ON public.wa_users (created_at DESC)","CREATE INDEX IF NOT EXISTS wa_users_source_type_idx\n  ON public.wa_users (source_type)"}	add_member_source_type_and_wa_users
20260426183000	{"ALTER TABLE public.submissions\n  ADD COLUMN IF NOT EXISTS source_type TEXT NOT NULL DEFAULT 'form'","ALTER TABLE public.submissions\n  ADD COLUMN IF NOT EXISTS source_external_id TEXT","DO $$\nBEGIN\n  ALTER TABLE public.submissions\n    DROP CONSTRAINT IF EXISTS submissions_source_type_check;\nEXCEPTION WHEN undefined_object THEN\n  NULL;\nEND $$","ALTER TABLE public.submissions\n  ADD CONSTRAINT submissions_source_type_check\n  CHECK (source_type IN ('form', 'chatbot', 'wa'))","UPDATE public.submissions\nSET source_type = 'chatbot'\nWHERE referral_source = 'ai-chat'\n  AND source_type <> 'chatbot'","CREATE UNIQUE INDEX IF NOT EXISTS submissions_source_external_unique_idx\nON public.submissions (source_type, source_external_id)\nWHERE source_external_id IS NOT NULL","INSERT INTO public.submissions (\n  form_type,\n  source_type,\n  source_external_id,\n  category,\n  fullname,\n  country,\n  city,\n  business,\n  field,\n  email,\n  phone,\n  description,\n  offers_needs,\n  referral_source,\n  referral_code,\n  whatsapp_interest,\n  consent,\n  status,\n  created_at\n)\nSELECT\n  'register',\n  'wa',\n  COALESCE(wa_id, id::text),\n  category,\n  COALESCE(NULLIF(TRIM(CONCAT_WS(' ', name, surname)), ''), phone, wa_id, 'WhatsApp kullanıcısı'),\n  COALESCE(NULLIF(country, ''), 'Belirtilmedi'),\n  COALESCE(NULLIF(city, ''), 'Belirtilmedi'),\n  organization,\n  COALESCE(\n    CASE\n      WHEN occupation_interest IS NULL THEN NULL\n      WHEN BTRIM(occupation_interest::text) IN ('', 'true', 'false') THEN NULL\n      ELSE BTRIM(occupation_interest::text)\n    END,\n    NULLIF(BTRIM(organization::text), ''),\n    NULLIF(BTRIM(funnel_interest::text), ''),\n    'WhatsApp Bot'\n  ),\n  COALESCE(NULLIF(email, ''), CONCAT(COALESCE(wa_id, id::text), '@wa.local')),\n  COALESCE(NULLIF(phone, ''), wa_id, ''),\n  note,\n  funnel_interest,\n  'whatsapp',\n  NULLIF(referral_code, ''),\n  COALESCE(whatsapp_group_interest, true),\n  COALESCE(privacy_consent, false),\n  CASE WHEN registration_status = 'completed' THEN 'contacted' ELSE 'new' END,\n  created_at\nFROM public.wa_users\nON CONFLICT (source_type, source_external_id) WHERE source_external_id IS NOT NULL DO NOTHING"}	unify_wa_submissions
20260503110000	{"CREATE TABLE IF NOT EXISTS public.lansman_registrations (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  first_name TEXT NOT NULL,\n  last_name TEXT NOT NULL,\n  initials TEXT,\n  phone TEXT NOT NULL,\n  linkedin TEXT NULL,\n  instagram TEXT NULL,\n  twitter TEXT NULL,\n  website TEXT NULL,\n  description TEXT NULL,\n  status TEXT NOT NULL DEFAULT 'pending',\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now()\n)","DO $$\nBEGIN\n  IF NOT EXISTS (\n    SELECT 1\n    FROM pg_constraint\n    WHERE conname = 'lansman_status_check'\n      AND conrelid = 'public.lansman_registrations'::regclass\n  ) THEN\n    ALTER TABLE public.lansman_registrations\n      ADD CONSTRAINT lansman_status_check\n      CHECK (status IN ('pending', 'approved', 'rejected'));\n  END IF;\nEND\n$$","CREATE INDEX IF NOT EXISTS lansman_registrations_status_idx\n  ON public.lansman_registrations (status)","CREATE INDEX IF NOT EXISTS lansman_registrations_created_at_idx\n  ON public.lansman_registrations (created_at DESC)","REVOKE ALL ON public.lansman_registrations FROM anon","REVOKE ALL ON public.lansman_registrations FROM authenticated","ALTER TABLE public.lansman_registrations ENABLE ROW LEVEL SECURITY","DO $$\nBEGIN\n  IF NOT EXISTS (\n    SELECT 1\n    FROM pg_policies\n    WHERE schemaname = 'public'\n      AND tablename = 'lansman_registrations'\n      AND policyname = 'Anyone can insert lansman registrations'\n  ) THEN\n    CREATE POLICY \\"Anyone can insert lansman registrations\\"\n      ON public.lansman_registrations\n      FOR INSERT\n      TO anon, authenticated\n      WITH CHECK (true);\n  END IF;\nEND\n$$","DO $$\nBEGIN\n  IF NOT EXISTS (\n    SELECT 1\n    FROM pg_policies\n    WHERE schemaname = 'public'\n      AND tablename = 'lansman_registrations'\n      AND policyname = 'Public pending lansman select'\n  ) THEN\n    CREATE POLICY \\"Public pending lansman select\\"\n      ON public.lansman_registrations\n      FOR SELECT\n      TO anon, authenticated\n      USING (status = 'pending');\n  END IF;\nEND\n$$","GRANT INSERT ON public.lansman_registrations TO anon, authenticated","REVOKE SELECT, UPDATE ON public.lansman_registrations FROM anon, authenticated","CREATE OR REPLACE VIEW public.lansman_pending_public AS\nSELECT\n  id,\n  initials,\n  status,\n  created_at\nFROM public.lansman_registrations\nWHERE status = 'pending'","GRANT SELECT ON public.lansman_pending_public TO anon, authenticated","COMMENT ON TABLE public.lansman_registrations IS\n  'MVP lansman registrations table. Public insert is allowed. Admin reads/updates should be handled via backend or edge function instead of frontend-only auth.'"}	add_lansman_registrations
